            elif predicate == "locationIdentifier":
                details.append(f"and has a location identifier of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                details.append(f"which is {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                details.append(f"with an IATA location identifier of {obj}")
            elif predicate == "nativeName":
                details.append(f"also known as {obj}")
            elif predicate == "leaderParty":
                details.append(f"with a leader party of {obj}")
            elif predicate == "runwayName":
                details.append(f"and has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                details.append(f"with a runway surface made of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                details.append(f"which is {obj} metres above sea level")
            elif predicate == "division":
                details.append(f"which belongs to the division of {obj}")
            elif predicate == "class":
                details.append(f"which belongs to the class of {obj}")
            else:
                # Handle other predicates with more natural phrasing
                if predicate == "elevationAboveTheSeaLevel" or predicate == "elevationAboveTheSeaLevelInMetres" or predicate == "elevationAboveTheSeaLevelInFeet":
                    # Already handled above
                    pass
                else:
                    # Use more natural phrasing for common cases
                    if predicate.endswith("Length") or predicate.endswith("LengthFeet") or predicate.endswith("LengthMetre"):
                        details.append(f"with a {predicate.replace('1stRunway', 'first runway').replace('2ndRunway', 'second runway').replace('3rdRunway', 'third runway').replace('4thRunway', 'fourth runway').replace('5thRunway', 'fifth runway').replace('Length', '').replace('Feet', '').replace('Metre', '')} of {obj}")
                    elif predicate == "country":
                        details.append(f"which is located in {obj}")
                    elif predicate == "location":
                        details.append(f"which is located in {obj}")
                    else:
                        # Use "is" instead of "has a ... of" where appropriate
                        if predicate in ["officialLanguage", "language", "capital"]:
                            details.append(f"is {obj}")
                        else:
                            details.append(f"has a {predicate} of {obj}")
        sentence += " " + ", ".join(details)
    return sentence + "."

